import React, { createContext, useContext, useReducer, useEffect, ReactNode } from 'react';
import { useAppNavigation } from './NavigationContext';
import { showNotification } from '../assets/notifications';
import { formatWelcomeMessage } from '../utils/nameFormatter';
import { useNavigationWithDelay } from '../hooks/useNavigationWithDelay';

interface User {
  _id: string;
  email: string;
  firstName: string;
  lastName: string;
  role: 'user' | 'admin';
}

interface RegisterData {
  email: string;
  firstName: string;
  lastName: string;
  password: string;
}

interface AuthState {
  user: User | null;
  token: string | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  error: string | null;
}

interface AuthContextType extends AuthState {
  login: (email: string, password: string) => Promise<void>;
  loginWithGoogle: () => Promise<void>;
  register: (userData: RegisterData) => Promise<void>;
  logout: () => void;
  clearError: () => void;
  updateUser: (user: User) => void;
  state: AuthState;
}

type AuthAction =
  | { type: 'LOGIN_START' }
  | { type: 'LOGIN_SUCCESS'; payload: { user: User; token: string } }
  | { type: 'LOGIN_FAILURE'; payload: string }
  | { type: 'LOGOUT' }
  | { type: 'CLEAR_ERROR' }
  | { type: 'SET_LOADING'; payload: boolean };

const authReducer = (state: AuthState, action: AuthAction): AuthState => {
  switch (action.type) {
    case 'LOGIN_START':
      return { ...state, isLoading: true, error: null };
    case 'LOGIN_SUCCESS':
      return {
        ...state,
        user: action.payload.user,
        token: action.payload.token,
        isAuthenticated: true,
        isLoading: false,
        error: null,
      };
    case 'LOGIN_FAILURE':
      return {
        ...state,
        user: null,
        token: null,
        isAuthenticated: false,
        isLoading: false,
        error: action.payload,
      };
    case 'LOGOUT':
      return {
        ...state,
        user: null,
        token: null,
        isAuthenticated: false,
        isLoading: false,
        error: null,
      };
    case 'CLEAR_ERROR':
      return { ...state, error: null };
    case 'SET_LOADING':
      return { ...state, isLoading: action.payload };
    default:
      return state;
  }
};

const initialState: AuthState = {
  user: null,
  token: localStorage.getItem('token'),
  isAuthenticated: !!localStorage.getItem('token'),
  isLoading: false,
  error: null,
};

interface AuthProviderProps {
  children: ReactNode;
}

export const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider: React.FC<AuthProviderProps> = ({ children }) => {
  const [state, dispatch] = useReducer(authReducer, initialState);
  const navigate = useAppNavigation();
  const { navigateWithDelay, redirectWithDelay, isLoading, setIsLoading } = useNavigationWithDelay();

  useEffect(() => {
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');
    if (token && userData) {
      try {
        const user = JSON.parse(userData);
        dispatch({
          type: 'LOGIN_SUCCESS',
          payload: { user, token },
        });
      } catch (error) {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        localStorage.removeItem('users');
        dispatch({ type: 'LOGOUT' });
      }
    }
  }, []);

  const login = async (email: string, password: string) => {
    dispatch({ type: 'LOGIN_START' });
    try {
      // ž¦┘äž¬žŁ┘é┘é ┘ģ┘å ž¦┘ä┘ģž│ž¬ž«ž»┘ģ┘Ŗ┘å ┘ü┘Ŗ localStorage
      const existingUsers = JSON.parse(localStorage.getItem('users') || '[]');
      const existingUser = existingUsers.find((u: User) => u.email === email);

      if (existingUser) {
        // ž¦┘ä┘ģž│ž¬ž«ž»┘ģ ┘ģ┘łž¼┘łž» - ž¬ž│ž¼┘Ŗ┘ä ž¦┘äž»ž«┘ł┘ä
        const token = `mock-jwt-token-${existingUser._id}`;
        localStorage.setItem('token', token);
        localStorage.setItem('user', JSON.stringify(existingUser));

        dispatch({
          type: 'LOGIN_SUCCESS',
          payload: { user: existingUser, token }
        });

        showNotification(formatWelcomeMessage(existingUser.firstName, existingUser.lastName), 'success');
        // ž¦┘äž¦┘åž¬┘éž¦┘ä ┘ä┘äžĄ┘üžŁž® ž¦┘äž▒ž”┘Ŗž│┘Ŗž® ┘ģž╣ ž¬žŻž«┘Ŗž▒ ┘ł loading
        navigateWithDelay('/', 2500);
      } else {
        // ž¦┘ä┘ģž│ž¬ž«ž»┘ģ ž║┘Ŗž▒ ┘ģ┘łž¼┘łž» - ┘Ŗž¼ž© žź┘åž┤ž¦žĪ žŁž│ž¦ž© žŻ┘ł┘äž¦┘ŗ
        throw new Error('┘ćž░ž¦ ž¦┘äžŁž│ž¦ž© ž║┘Ŗž▒ ┘ģ┘łž¼┘łž». ┘Ŗž▒ž¼┘ē žź┘åž┤ž¦žĪ žŁž│ž¦ž© žŻ┘ł┘äž¦┘ŗ.');
      }
    } catch (error: any) {
      const errorMessage = error.message || '┘üž┤┘ä ž¬ž│ž¼┘Ŗ┘ä ž¦┘äž»ž«┘ł┘ä';
      dispatch({ type: 'LOGIN_FAILURE', payload: errorMessage });
      throw error;
    }
  };

  const loginWithGoogle = async () => {
    try {
      dispatch({ type: 'LOGIN_START' });

      // Google Client ID ┘ģ┘å Google Cloud Console
      const GOOGLE_CLIENT_ID = '866642345311-4kiub26p4228g5q7edh3svh05vmn19gn.apps.googleusercontent.com';

      // Redirect to Google OAuth using simple URL
      const googleAuthUrl = `https://accounts.google.com/o/oauth2/v2/auth?` +
        `client_id=${GOOGLE_CLIENT_ID}&` +
        `redirect_uri=${encodeURIComponent('http://localhost:3000/auth/google/callback')}&` +
        `response_type=code&` +
        `scope=${encodeURIComponent('openid profile email')}&` +
        `access_type=offline&` +
        `prompt=consent`;

      window.location.href = googleAuthUrl;
    } catch (error: any) {
      const errorMessage = error.response?.data?.message || '┘üž┤┘ä ž¬ž│ž¼┘Ŗ┘ä ž¦┘äž»ž«┘ł┘ä ž╣ž©ž▒ Google';
      dispatch({ type: 'LOGIN_FAILURE', payload: errorMessage });
      throw error;
    }
  };

const register = async (userData: RegisterData) => {
    try {
      dispatch({ type: 'LOGIN_START' });

      // ┘ģžŁž¦┘āž¦ž® žź┘åž┤ž¦žĪ žŁž│ž¦ž© ┘åž¦ž¼žŁ (┘ü┘Ŗ ž¦┘ä┘łž¦┘éž╣ ┘Ŗž¼ž© žŻ┘å ┘Ŗ┘ā┘ł┘å ┘ćž░ž¦ API call)
      await new Promise(resolve => setTimeout(resolve, 1000));

      // ž¦┘äž¬žŁ┘é┘é ┘ģ┘å ┘łž¼┘łž» ┘ģž│ž¬ž«ž»┘ģ ž©┘å┘üž│ ž¦┘äžź┘Ŗ┘ģ┘Ŗ┘ä
      const existingUsers = JSON.parse(localStorage.getItem('users') || '[]');
      const existingUser = existingUsers.find((u: User) => u.email === userData.email);

      if (existingUser) {
        throw new Error('ž¦┘äž©ž▒┘Ŗž» ž¦┘äžź┘ä┘āž¬ž▒┘ł┘å┘Ŗ ┘ģž│ž¬ž«ž»┘ģ ž©ž¦┘ä┘üž╣┘ä');
      }

      const user = {
        _id: Date.now().toString(),
        email: userData.email,
        firstName: userData.firstName,
        lastName: userData.lastName,
        role: 'user' as const,
      };
      const token = `mock-jwt-token-${user._id}`;

      // žŁ┘üžĖ ž¦┘ä┘ģž│ž¬ž«ž»┘ģ ┘ü┘Ŗ ┘éž¦ž”┘ģž® ž¦┘ä┘ģž│ž¬ž«ž»┘ģ┘Ŗ┘å
      existingUsers.push(user);
      localStorage.setItem('users', JSON.stringify(existingUsers));

      localStorage.setItem('token', token);
      localStorage.setItem('user', JSON.stringify(user));
      dispatch({
        type: 'LOGIN_SUCCESS',
        payload: { user, token },
      });

      // ž¦┘äž¦┘åž¬┘éž¦┘ä žź┘ä┘ē žĄ┘üžŁž® ž¦┘ä┘ģ┘ä┘ü ž¦┘äž┤ž«žĄ┘Ŗ ž©ž╣ž» žź┘åž┤ž¦žĪ ž¦┘äžŁž│ž¦ž©
      // ž│┘Ŗž¬┘ģ ž¦┘äž¬ž╣ž¦┘ģ┘ä ┘ģž╣ ž¦┘äž¦┘åž¬┘éž¦┘ä ┘ü┘Ŗ ž¦┘äžĄ┘üžŁž®
    } catch (error: any) {
      const errorMessage = error.message || '┘üž┤┘ä žź┘åž┤ž¦žĪ ž¦┘äžŁž│ž¦ž©';
      dispatch({ type: 'LOGIN_FAILURE', payload: errorMessage });
      throw error;
    }
  };

  const logout = () => {
    dispatch({ type: 'LOGOUT' });
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    localStorage.removeItem('users');
    showNotification('ž¬┘ģ ž¬ž│ž¼┘Ŗ┘ä ž¦┘äž«ž▒┘łž¼ ž©┘åž¼ž¦žŁ', 'success');
    // ž¦┘äž¦┘åž¬┘éž¦┘ä ┘ä┘äžĄ┘üžŁž® ž¦┘äž▒ž”┘Ŗž│┘Ŗž® ┘ģž╣ ž¬žŻž«┘Ŗž▒ ┘ł loading
    redirectWithDelay('/', 2500);
  };

  // ž¬žŁž»┘Ŗž½ ž©┘Ŗž¦┘åž¦ž¬ ž¦┘ä┘ģž│ž¬ž«ž»┘ģ ┘ü┘Ŗ ž¦┘äžŁž¦┘äž®
  const updateUser = (updatedUser: User) => {
    if (state.token) {
      dispatch({
        type: 'LOGIN_SUCCESS',
        payload: { user: updatedUser, token: state.token }
      });
    }
  };

  const clearError = () => {
    dispatch({ type: 'CLEAR_ERROR' });
  };

  const value: AuthContextType = {
    user: state.user,
    token: state.token,
    isAuthenticated: state.isAuthenticated,
    isLoading: state.isLoading,
    error: state.error,
    state,
    login,
    loginWithGoogle,
    register,
    logout,
    clearError,
    updateUser,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};
